INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (0, 1, 110, 1.5, 1, 160, 0, 122601, 105, 1, 101, "仲間と夏を楽しむ、夏海の魔法士。自分を変えたいという固い決意で、障害物を無効化して走り続ける。", 1, 0.029);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (1, 3, 105, 2.5, 2, 120, 0, 122401, 111, 0, 102, "太陽よりも輝く、夏海の元気娘。　持ち前の身体能力で、どんなコースも柔軟に対応し、駆け抜ける。", 2, 0.014);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (0, 2, 110, 2.5, 3, 350, 1, 122501, 105, 0, 103, "波打ち際に煌めく、夏海の剣士。　日々の鍛錬で鍛えた脚で、長い距離も速度を落とさず走り切る。", 3, 0.017);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (1, 3, 110, 1.5, 4, 130, 0, 107501, 105, 0, 104, "海の幸に目がない、渚のお姫様。　『王家の装備』の力を解放し、障害物をものともせず前へと進む。", 4, 0.016);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (0, 1, 110, 2.5, 5, 160, 0, 107601, 105, 1, 105, "海でも主さまをお世話する、白浜の巫女。精霊の力で自身を加速させ、誰よりも速くゴールを目指す。", 5, 0.014);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (0, 2, 120, 3.5, 6, 255, 1, 107801, 103, 0, 106, "水着姿を恥じらう、ツンデレ猫娘。お得意の魔法で、対戦相手の走りを妨害し、レースを有利に進める。", 6, 0.029);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (0, 1, 120, 3.5, 7, 160, 0, 110601, 103, 1, 107, "優雅に浜を駆ける、真夏のマホ姫。しゃなりしゃなりと、雅な身のこなしで障害物を跳び越えていく。", 7, 0.013);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (0, 2, 110, 2.5, 8, 350, 1, 110401, 103, 0, 108, "浜の平和を守る、真夏の狼娘。　　獣人の強靭なスタミナで、レース　後半にスパートをかける。", 8, 0.014);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (1, 3, 105, 1.5, 9, 130, 0, 110501, 100, 0, 109, "浜に力強く舞う、真夏の南国娘。　レースの喧噪の中でも精神を乱さず後半に大きな捲りを見せる。", 9, 0.012);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (0, 1, 105, 2.5, 10, 200, 0, 115701, 103, 1, 110, "浜の事件を嗅ぎ付けた、真夏の　　名探偵。高い推理力と魔法で、的確に対戦相手の走りを乱す。", 10, 0.014);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (0, 2, 105, 2.5, 11, 350, 1, 113601, 103, 0, 111, "再び鎧を脱いだ、灼熱の騎士団長。実戦で培った判断力で、瞬時にバリアを展開し、障害物を無力化する。", 11, 0.071);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (1, 3, 120, 1.5, 12, 130, 0, 107901, 103, 0, 112, "水が苦手な、海辺の気まぐれ猫娘。浜に現れた美少女義賊は、対戦相手のスピードを奪いとる。", 12, 0.014);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (0, 2, 110, 1.5, 13, 200, 0, 108001, 105, 1, 113, "バカンスも効率第一な、海の傭兵。レースでも最高効率を求め、どんな状況でも隙のない走りを見せる。", 13, 0.022);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (0, 1, 110, 2.5, 14, 160, 0, 110301, 108, 1, 114, "真夏の太陽が良く似合う、海辺の　サレンママ。多才で器用、どんな　障害物もエレガントに越えていく。", 14, 0.031);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (1, 1, 110, 0.5, 15, 130, 0, 107701, 105, 0, 115, "海に嵐を呼ぶ夏のドジっ娘メイド。日頃から災難に慣れており、多少　のトラブルには動じたりしない。", 15, 0.036);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (0, 2, 110, 3.5, 16, 350, 1, 113101, 95, 0, 116, "粋な夏を愉しむ、若夏の姉御。　　流麗な身体捌きで、始・継・終と、UBを重ねるごとに、加速する。", 16, 0.048);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (1, 3, 105, 1.5, 17, 130, 0, 113301, 105, 0, 117, "夏のトキメキに触れた、オタク魔法少女。多彩な魔法を操り、少しずつ他の走者の速度を落とし続ける。", 17, 0.043);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (1, 2, 105, 1.5, 18, 130, 0, 113201, 95, 0, 118, "海獄に降臨せし、真夏の冥姫。　　レース後半に魔力を全解放し、　　蒼き疾風と成りて浜を駆け抜ける。", 18, 0.018);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (0, 2, 110, 2.5, 19, 160, 0, 117001, 108, 1, 119, "夏の夕を火花で彩る、渚の壊し屋。『壊し屋』の異名と過激な愛情は、対戦相手にプレッシャーを与える。", 19, 0.021);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (0, 1, 110, 2.5, 20, 255, 1, 113501, 105, 0, 120, "青春に生きる者を導く、夏の先生。夢へと邁進する聖母の加護が、その身をあらゆる困難から守る。", 20, 0.036);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (0, 3, 105, 2.5, 21, 350, 1, 113401, 105, 0, 121, "笑顔の応援が眩しい、夏の超能力　ガール。超能力を駆使して、どんな障害物もひとっ飛びで乗り越える。", 21, 0.02);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (1, 1, 110, 2.5, 22, 130, 0, 110101, 105, 0, 122, "海辺で大人の魅力を放つ、夏の　　セクシー先生。その魅力に囚われた対戦相手は、走りを乱してしまう。", 22, 0.018);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (0, 3, 105, 3.5, 23, 160, 0, 110001, 111, 1, 123, "水着も絶対外さない、夏のカリスマモデル。走りのバイブスは超テンアゲで、スピードはおにやば。", 23, 0.03);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (1, 1, 110, 1.5, 24, 130, 0, 117201, 103, 0, 124, "南の島も盛り上げる、真夏のアイドル。悪天候でも笑顔を絶やさず後半もリズムを上げて走り切る。", 24, 0.027);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (0, 2, 105, 3.5, 25, 160, 0, 117301, 108, 1, 125, "海原に美声を響かす、渚の歌姫。　守護の賛歌と精霊の加護により、　障害物から身を守る。", 25, 0.02);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (0, 3, 110, 2.5, 26, 350, 1, 117401, 105, 0, 126, "夏でも天邪鬼な、夕凪のテーラー。張り巡らされた魔法の糸で、他の走者の自由を奪う。", 26, 0.04);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (0, 1, 110, 3.5, 27, 350, 1, 117101, 105, 0, 127, "向日葵が良く似合う、海辺の　　　お姉ちゃん。秘密結社の一員で、　抜群の身体能力が一番の武器。", 27, 0.009);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (0, 1, 120, 3.5, 28, 255, 1, 122901, 105, 0, 128, "渚でおっとり、夏色うさぎっこ。　うさぎさんパワー全開で、ぴょん　ぴょんとコースを跳ね回る。", 28, 0.022);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (1, 3, 110, 2.5, 29, 130, 0, 122801, 105, 0, 129, "無邪気さ弾ける、夏色いたずら娘。砂浜でも、いたずらの準備は万端！レースに大波乱が巻き起こる！？", 29, 0.028);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (0, 2, 105, 3.5, 30, 130, 0, 122701, 108, 1, 130, "海でも真面目な、夏色優等生。　　高めた魔力を解き放ち、一瞬の内に他の走者を置き去りにする。", 30, 0.023);
